function quotePriceText(q){return q.currency==='KRW'?`${nf.format(q.price)}원`:`${esc(q.currency||'USD')} ${nf.format(q.price)}`}
function ownedStockView(row,compact=false){
  const q=row.quote,change=q&&typeof q.change_percent==='number'?`${q.change_percent>=0?'+':''}${q.change_percent.toFixed(2)}%`:'-';
  const hasBasis=Number(row.buyPrice)>0&&Number(row.quantity)>0&&q,pnl=hasBasis?(Number(q.price)-Number(row.buyPrice))*Number(row.quantity):null;
  const pnlText=pnl===null?'매수가·수량 미입력':`${pnl>=0?'+':''}${q.currency==='KRW'?nf.format(Math.round(pnl))+'원':(q.currency||'USD')+' '+nf.format(pnl)}`;
  if(compact)return `<div class="home-owned-row"><div class="home-owned-body"><div class="home-owned-main"><strong>${esc(q?.company||row.symbol)}</strong><span>${esc(q?.ticker||row.symbol)} · 최근 조회 시세 · 지연 가능</span></div><div class="home-owned-stats"><div class="home-owned-stat home-owned-price"><span>최근 가격</span><strong>${q?quotePriceText(q):'조회 전'}</strong></div><div class="home-owned-stat home-owned-change"><span>전일 대비</span><strong class="${q&&Number(q.change_percent)<0?'negative':q&&Number(q.change_percent)>0?'income':''}">${esc(change)}</strong></div><div class="home-owned-stat home-owned-pnl"><span>매수가 기준 손익</span><strong class="${pnl!==null&&pnl<0?'negative':pnl!==null&&pnl>0?'income':''}">${esc(pnlText)}</strong></div></div></div><button class="home-owned-refresh" title="이 종목 다시 조회" onclick="refreshOwnedStock('${esc(row.id)}')">↻</button></div>`;
  return `<div class="owned-stock-row"><div class="owned-main"><strong>${esc(q?.company||row.symbol)}</strong><span>${esc(q?.ticker||row.symbol)} · 최근 조회 시세${q?' · 지연 가능':''}</span></div><div class="owned-stat"><span>최근 가격</span><strong>${q?quotePriceText(q):'조회 전'}</strong></div><div class="owned-stat"><span>전일 대비</span><strong class="${q&&Number(q.change_percent)<0?'negative':q&&Number(q.change_percent)>0?'income':''}">${esc(change)}</strong></div><div class="owned-stat pnl"><span>매수가 기준 손익</span><strong class="${pnl!==null&&pnl<0?'negative':pnl!==null&&pnl>0?'income':''}">${esc(pnlText)}</strong></div><div class="owned-actions"><button title="다시 조회" onclick="refreshOwnedStock('${esc(row.id)}')">↻</button><button title="삭제" onclick="removeOwnedStock('${esc(row.id)}')">×</button></div></div>`
}
function renderOwnedStocks(){
  const rows=Array.isArray(app.ownedStocks)?app.ownedStocks:[],list=$('#ownedStockList'),homeList=$('#homeOwnedStockList');
  if(list)list.innerHTML=rows.length?rows.map(row=>ownedStockView(row,false)).join(''):'<div class="empty">등록한 보유 종목이 없습니다.</div>';
  if(homeList)homeList.innerHTML=rows.length?rows.slice(0,4).map(row=>ownedStockView(row,true)).join(''):'<div class="empty">주식 인텔리전스에서 보유 종목을 등록하면 여기에 표시됩니다.</div>';
}
async function addOwnedStock(){
  const symbol=$('#ownedStockSymbol').value.trim();if(!symbol)return showToast('기업명 또는 티커를 입력해 주세요.');
  const normalized=symbol.toUpperCase(),existing=app.ownedStocks.find(x=>String(x.symbol).toUpperCase()===normalized);
  const item={id:existing?.id||`stock-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,symbol,buyPrice:Number($('#ownedStockBuyPrice').value)||0,quantity:Number($('#ownedStockQuantity').value)||0,addedAt:existing?.addedAt||new Date().toISOString(),quote:existing?.quote||null};
  app.ownedStocks=existing?app.ownedStocks.map(x=>x.id===existing.id?item:x):[item,...app.ownedStocks].slice(0,20);
  writeLocal('nexus-owned-stocks-v82',app.ownedStocks);$('#ownedStockSymbol').value='';$('#ownedStockBuyPrice').value='';$('#ownedStockQuantity').value='';renderOwnedStocks();await refreshOwnedStock(item.id)
}
async function refreshOwnedStock(id){
  const row=app.ownedStocks.find(x=>x.id===id);if(!row)return;
  const notes=[$('#ownedStockRefreshNote'),$('#homeOwnedStockRefreshNote')].filter(Boolean);notes.forEach(note=>note.textContent=`${row.symbol} 시세를 다시 확인하는 중…`);
  try{const result=await invokeStock({mode:'quote',symbol:row.symbol});row.quote=result.quote;writeLocal('nexus-owned-stocks-v82',app.ownedStocks);renderOwnedStocks();notes.forEach(note=>note.textContent=`마지막 갱신 ${new Date().toLocaleTimeString('ko-KR')} · 지연 가능 가격`)}
  catch(error){notes.forEach(note=>note.textContent=`${row.symbol} 조회 실패: ${error instanceof Error?error.message:String(error)}`)}
}
async function refreshOwnedStocks(){for(const row of app.ownedStocks)await refreshOwnedStock(row.id)}
function removeOwnedStock(id){app.ownedStocks=app.ownedStocks.filter(x=>x.id!==id);writeLocal('nexus-owned-stocks-v82',app.ownedStocks);renderOwnedStocks()}
function clearOwnedStockTimer(){if(app.ownedStockTimer){clearInterval(app.ownedStockTimer);app.ownedStockTimer=null}}
function scheduleOwnedStockRefresh(){clearOwnedStockTimer();if(!['stocks','home'].includes(app.currentPage)||!app.ownedStocks.length)return;app.ownedStockTimer=setInterval(()=>{if(['stocks','home'].includes(app.currentPage))refreshOwnedStocks()},60000)}

function currentWeekWorkoutCount(){const since=new Date();since.setDate(since.getDate()-6);since.setHours(0,0,0,0);return app.fitnessRecords.filter(r=>r.kind==='workout'&&new Date(r.date)>=since).length}
function inspectFiveMCfg(){
  const input=$('#fivemCfgInput');if(!input)return;const raw=input.value||'',lines=raw.split(/\r?\n/),active=lines.map((line,index)=>({line:index+1,text:line.trim()})).filter(x=>x.text&&!x.text.startsWith('#')&&!x.text.startsWith('//'));
  const ensures=active.map(x=>{const m=x.text.match(/^(?:ensure|start)\s+([^\s#]+)/i);return m?{name:m[1],line:x.line}:null}).filter(Boolean),lower=ensures.map(x=>x.name.toLowerCase()),duplicates=[...new Set(lower.filter((name,i)=>lower.indexOf(name)!==i))];
  const hasTcp=active.some(x=>/^endpoint_add_tcp\b/i.test(x.text)),hasUdp=active.some(x=>/^endpoint_add_udp\b/i.test(x.text)),hasLicense=active.some(x=>/^(?:set\s+)?sv_licensekey\b/i.test(x.text)),hasMysql=active.some(x=>/(mysql_connection_string|oxmysql|mysql-async|ghmattimysql)/i.test(x.text)),hasHostname=active.some(x=>/^sv_hostname\b/i.test(x.text)),hasMax=active.some(x=>/^sv_maxclients\b/i.test(x.text)),hasOneSync=active.some(x=>/onesync/i.test(x.text));
  const dbIndex=lower.findIndex(name=>/(oxmysql|mysql-async|ghmattimysql)/.test(name)),vrpIndex=lower.findIndex(name=>/(^|[_-])vrp($|[_-])|^vrp$/i.test(name));
  const findings=[];
  const add=(type,title,copy)=>findings.push({type,title,copy});
  if(!active.length)add('watch','붙여넣은 설정이 비어 있어요','주석이 아닌 server.cfg 설정 줄을 붙여넣어 주세요.');
  if(hasTcp&&hasUdp)add('good','TCP·UDP endpoint 확인','기본 접속 endpoint 두 줄이 모두 보입니다.');else add('watch','endpoint 확인 필요',`TCP ${hasTcp?'확인':'없음'} · UDP ${hasUdp?'확인':'없음'}입니다. 서버 포트 설정을 다시 확인하세요.`);
  if(hasLicense)add('good','FiveM 라이선스 키 설정 줄 확인','키 값은 화면에 표시하지 않았습니다.');else add('watch','sv_licenseKey 설정 줄을 찾지 못했어요','실제 배포 server.cfg라면 라이선스 키 설정 줄이 있는지 확인하세요.');
  if(hasMysql)add('good','DB 연결 관련 설정 확인','MySQL 연결 문자열 또는 DB 드라이버 리소스가 보입니다. 민감한 연결 값은 결과에 표시하지 않습니다.');else add('watch','DB 연결 설정을 찾지 못했어요','vRP가 DB를 사용하는 구성이라면 MySQL 연결 문자열과 DB 드라이버 로드를 확인하세요.');
  if(vrpIndex>=0&&dbIndex>=0&&vrpIndex<dbIndex)add('bad','vRP보다 DB 드라이버가 늦게 로드돼요',`${ensures[vrpIndex].name}보다 ${ensures[dbIndex].name}가 뒤에 있습니다. DB 드라이버를 프레임워크보다 먼저 ensure 하는 편이 안전합니다.`);else if(vrpIndex>=0&&dbIndex>=0)add('good','DB 드라이버 → vRP 로드 순서 확인',`${ensures[dbIndex].name}가 ${ensures[vrpIndex].name}보다 먼저 로드됩니다.`);
  if(duplicates.length)add('bad','중복 ensure가 있어요',duplicates.map(name=>`${name}`).join(', '));else if(ensures.length)add('good','중복 ensure 없음',`${ensures.length}개 리소스 로드 줄에서 같은 이름의 중복을 찾지 못했습니다.`);
  if(!hasHostname)add('info','서버 이름 설정을 확인해 보세요','sv_hostname 줄을 찾지 못했습니다. 별도 include 구조라면 그대로 둘 수 있어요.');
  if(!hasMax)add('info','최대 접속자 설정 확인','sv_maxclients 줄을 찾지 못했습니다.');
  if(hasOneSync)add('good','OneSync 관련 설정 확인','OneSync 문자열이 포함된 설정 줄이 보입니다.');
  const score=findings.filter(x=>x.type==='bad').length?'수정 필요':findings.filter(x=>x.type==='watch').length?'확인 필요':'양호';
  $('#fivemCfgSummary').innerHTML=`<div><span>활성 설정</span><strong>${active.length}줄</strong></div><div><span>로드 리소스</span><strong>${ensures.length}개</strong></div><div><span>중복 ensure</span><strong>${duplicates.length}개</strong></div><div><span>점검 결과</span><strong>${score}</strong></div>`;
  $('#fivemCfgFindings').innerHTML=findings.map(item=>`<div class="fivem-finding ${item.type}"><b>${item.type==='good'?'✓':item.type==='bad'?'!':item.type==='watch'?'?':'i'}</b><div><strong>${esc(item.title)}</strong><span>${esc(item.copy)}</span></div></div>`).join('');
}
function clearFiveMCfg(){const input=$('#fivemCfgInput');if(input)input.value='';$('#fivemCfgSummary').innerHTML='<div><span>활성 설정</span><strong>-</strong></div><div><span>로드 리소스</span><strong>-</strong></div><div><span>중복 ensure</span><strong>-</strong></div><div><span>점검 결과</span><strong>대기</strong></div>';$('#fivemCfgFindings').innerHTML='<div class="empty">server.cfg를 붙여넣고 설정 점검을 실행하세요.</div>'}
function saveFiveMData(){writeLocal('nexus-fivem-dev-v90',app.fivemData)}
function addFiveMResource(){const name=($('#fivemResourceName').value||'').trim(),path=($('#fivemResourcePath').value||'').trim(),status=$('#fivemResourceStatus').value;if(!name)return showToast('리소스 이름을 입력해 주세요.');app.fivemData.resources=[{id:`res-${Date.now()}-${Math.random().toString(36).slice(2,6)}`,name,path,status,updatedAt:new Date().toISOString()},...(app.fivemData.resources||[])].slice(0,30);saveFiveMData();$('#fivemResourceName').value='';renderFiveMPage();showToast('FiveM 리소스 작업 보드에 추가했습니다.')}
function updateFiveMResource(id,status){const row=(app.fivemData.resources||[]).find(x=>x.id===id);if(!row)return;row.status=status;row.updatedAt=new Date().toISOString();saveFiveMData();renderFiveMPage()}
function removeFiveMResource(id){app.fivemData.resources=(app.fivemData.resources||[]).filter(x=>x.id!==id);saveFiveMData();renderFiveMPage()}
function detectFiveMScriptType(raw,selected='auto'){if(selected&&selected!=='auto')return selected;if(/\binterface\s+\w+|\btype\s+\w+\s*=|:\s*(?:number|string|boolean|Record<|any|Promise<)/.test(raw))return'ts';if(/Citizen\.CreateThread|CreateThread\(|RegisterNetEvent\(|AddEventHandler\(|local\s+\w+\s*=|\bWait\(/.test(raw))return'lua';if(/setTick\(|onNet\(|emitNet\(|exports\.|const\s+\w+\s*=|let\s+\w+\s*=/.test(raw))return'js';return'auto'}
function inspectFiveMScript(){const input=$('#fivemScriptInput');if(!input)return;const raw=input.value||'',selected=$('#fivemScriptType').value||'auto',type=detectFiveMScriptType(raw,selected),lines=raw.split(/\r?\n/),active=lines.map((line,index)=>({line:index+1,text:line.trim()})).filter(x=>x.text&&!/^(?:--|#|\/\/|\/\*|\*)/.test(x.text)),findings=[];const add=(severity,title,copy)=>findings.push({severity,title,copy});const loopCount=(raw.match(/while\s+true\s+do|for\s*\(|for\s+.+\s+in\s+ipairs|for\s+.+\s+in\s+pairs|setTick\s*\(/g)||[]).length,eventCount=(raw.match(/RegisterNetEvent|AddEventHandler|onNet\s*\(|emitNet\s*\(|TriggerClientEvent|TriggerServerEvent/g)||[]).length,waitZeroCount=(raw.match(/(?:Citizen\.)?Wait\s*\(\s*0\s*\)|await\s+Delay\s*\(\s*0\s*\)/g)||[]).length,waitLowCount=(raw.match(/(?:Citizen\.)?Wait\s*\(\s*[1-9]\d?\s*\)|await\s+Delay\s*\(\s*[1-9]\d?\s*\)/g)||[]).length,printCount=(raw.match(/\bprint\s*\(|console\.log\s*\(/g)||[]).length,queryCount=(raw.match(/oxmysql|mysql-async|ghmattimysql|MySQL\.|exports\.oxmysql/g)||[]).length,playerLoopCount=(raw.match(/GetPlayers\s*\(|GetActivePlayers\s*\(|for\s+_,\s*player/gi)||[]).length;
if(!active.length){add('watch','붙여넣은 코드가 비어 있어요','분석할 Lua / JS / TS 코드가 보이지 않습니다. 주석이 아닌 실제 코드를 붙여넣어 주세요.')}else{
  const chunks=[];for(let i=0;i<lines.length;i++){if(/while\s+true\s+do|setTick\s*\(|for\s*\(;;\)/.test(lines[i]))chunks.push({line:i+1,code:lines.slice(i,Math.min(lines.length,i+16)).join('\n')})}
  for(const chunk of chunks){if(/while\s+true\s+do/.test(chunk.code)&&!/(?:Citizen\.)?Wait\s*\(/.test(chunk.code))add('bad',`무한 루프에 Wait가 없어요 (줄 ${chunk.line})`,'무한 루프가 쉬지 않고 돌면 프레임과 서버 시간을 크게 잡아먹습니다. sleep 변수나 이벤트 기반 처리로 바꾸세요.');if(/(?:Citizen\.)?Wait\s*\(\s*0\s*\)/.test(chunk.code))add('bad',`0프레임 루프가 보여요 (줄 ${chunk.line})`,'필요한 순간에만 0~5ms로 짧게 돌리고, 평소에는 250~1000ms 이상으로 늘리거나 이벤트 기반으로 바꾸는 편이 안전합니다.');if(/GetPlayers\s*\(|GetActivePlayers\s*\(|for\s+_,\s*player/i.test(chunk.code)&&/(?:Citizen\.)?Wait\s*\(\s*0\s*\)|setTick\s*\(/.test(chunk.code))add('watch',`플레이어 전체 순회가 잦을 수 있어요 (줄 ${chunk.line})`,'매 틱마다 전체 플레이어를 도는 구조는 인원이 늘수록 부담이 커집니다. 주기 늘리기, 캐시 사용, 근처 플레이어만 검사하는 구조를 권장합니다.');if(/oxmysql|mysql-async|ghmattimysql|MySQL\.|exports\.oxmysql/.test(chunk.code)&&(/while\s+true\s+do|setTick\s*\(|for\s+.+\s+in\s+ipairs|for\s+.+\s+in\s+pairs|for\s*\(/.test(chunk.code)))add('bad',`반복문 안에서 DB 쿼리가 보일 수 있어요 (줄 ${chunk.line})`,'루프마다 DB를 호출하면 서버 렉이 심해질 수 있습니다. 캐시를 두거나 이벤트가 발생했을 때만 쿼리하세요.');}
  if(/TriggerClientEvent\s*\([^,]+,\s*-1\b|emitNet\s*\([^,]+,\s*-1\b/.test(raw))add('watch','전체 브로드캐스트 이벤트가 보여요','모든 플레이어에게 매번 보내는 이벤트는 트래픽과 클라이언트 부하를 키울 수 있습니다. 꼭 필요한 경우가 아니라면 대상 범위를 줄여 보세요.');
  if(printCount>=8)add('info','디버그 출력이 많아요',`print / console.log가 ${printCount}회 보입니다. 개발 중에는 괜찮지만 운영 서버에서는 콘솔 스팸과 디스크 I/O가 늘 수 있어요.`);
  if(/RegisterNetEvent|onNet\s*\(/.test(raw)&&/(money|cash|bank|item|inventory|reward|vehicle|garage)/i.test(raw)&&!/\bsource\b|xPlayer|Player\(source\)|vRP\./.test(raw))add('watch','이벤트 검증 로직이 약할 수 있어요','돈·아이템·차량 관련 이벤트처럼 보이는데 권한/소유자/source 검증 흔적이 약합니다. 서버측 검증을 한 번 더 넣는 편이 안전합니다.');
  if(/GetEntityCoords|PlayerPedId|GetVehiclePedIsIn|GetGameplayCamCoord/.test(raw)&&waitZeroCount>0)add('watch','무거운 네이티브 호출이 자주 반복될 수 있어요','좌표·차량·카메라 관련 네이티브를 매 프레임 반복하면 클라이언트 부하가 커질 수 있습니다. 값 캐시와 조건부 갱신을 고려해 보세요.');
  if(!findings.length)add('good','큰 위험 패턴은 바로 보이지 않아요','현재 코드 조각에서는 눈에 띄는 렉 유발 패턴이 적습니다. 그래도 실제 플레이어 수 기준으로 프로파일링은 한 번 더 해보세요.');
}
const bad=findings.filter(x=>x.severity==='bad').length,watch=findings.filter(x=>x.severity==='watch').length;const risk=bad?'높음':watch>=2?'보통':'낮음';const priority=bad?'루프 / DB / 이벤트':watch?'주기 / 범위 줄이기':'유지';
$('#fivemScriptSummary').innerHTML=`<div><span>감지 언어</span><strong>${type==='auto'?'일반 스크립트':type==='lua'?'Lua':type==='ts'?'TypeScript':'JavaScript'}</strong></div><div><span>유효 코드</span><strong>${active.length}줄 · 루프 ${loopCount}개</strong></div><div><span>렉 위험도</span><strong>${risk}</strong></div><div><span>최적화 우선</span><strong>${priority}</strong></div>`;
$('#fivemScriptFindings').innerHTML=findings.map(item=>`<div class="fivem-finding ${item.severity}"><b>${item.severity==='good'?'✓':item.severity==='bad'?'!':item.severity==='watch'?'?':'i'}</b><div><strong>${esc(item.title)}</strong><span>${esc(item.copy)}</span></div></div>`).join('');
app.fivemData.lastInspection={type,activeLines:active.length,loopCount,eventCount,waitZeroCount,waitLowCount,printCount,queryCount,playerLoopCount,risk,priority,at:new Date().toISOString()};saveFiveMData();renderFiveMPage()}
function clearFiveMScript(){const input=$('#fivemScriptInput');if(input)input.value='';$('#fivemScriptSummary').innerHTML='<div><span>감지 언어</span><strong>-</strong></div><div><span>유효 코드</span><strong>-</strong></div><div><span>렉 위험도</span><strong>대기</strong></div><div><span>최적화 우선</span><strong>-</strong></div>';$('#fivemScriptFindings').innerHTML='<div class="empty">스크립트를 붙여넣고 점검을 실행하면 렉 유발 가능성과 최적화 포인트를 정리합니다.</div>'}
function saveFiveMWorkNotes(){app.fivemData.workNotes=$('#fivemWorkNotes').value||'';saveFiveMData();renderFiveMPage();showToast('FiveM 작업 메모를 저장했습니다.')}
function clearFiveMWorkNotes(){if($('#fivemWorkNotes'))$('#fivemWorkNotes').value='';app.fivemData.workNotes='';saveFiveMData();renderFiveMPage();showToast('FiveM 작업 메모를 지웠습니다.')}
function renderFiveMPage(){
  if(!$('#fivemResourceList'))return;const resources=app.fivemData.resources||[],last=app.fivemData.lastInspection||null;
  $('#fivemResourceList').innerHTML=resources.length?resources.map(row=>`<div class="fivem-resource-row"><div><strong>${esc(row.name)}</strong><span>${esc(row.path||'경로 미입력')}</span></div><select onchange="updateFiveMResource('${esc(row.id)}',this.value)"><option ${row.status==='작업 중'?'selected':''}>작업 중</option><option ${row.status==='점검 필요'?'selected':''}>점검 필요</option><option ${row.status==='완료'?'selected':''}>완료</option></select><button title="삭제" onclick="removeFiveMResource('${esc(row.id)}')">×</button></div>`).join(''):'<div class="empty">작업 중인 리소스를 추가하면 여기에 정리됩니다.</div>';
  if($('#fivemWorkNotes')&&document.activeElement!==$('#fivemWorkNotes'))$('#fivemWorkNotes').value=app.fivemData.workNotes||'';
  $('#fivemWorkHint').innerHTML=last?`마지막 스크립트 점검: <strong>${new Date(last.at).toLocaleString('ko-KR')}</strong> · 감지 언어 <strong>${last.type==='lua'?'Lua':last.type==='ts'?'TypeScript':last.type==='js'?'JavaScript':'일반 스크립트'}</strong> · 렉 위험도 <strong>${last.risk}</strong> · 우선 수정 <strong>${last.priority}</strong>.`:'server.cfg와 스크립트 점검 결과를 같이 보면서 수정 순서를 적어두면 작업 흐름을 유지하기 쉬워요.';
}

function renderHome(){
  const totals=financeTotals(),stats=monthStats(),latest=latestInbody();
  $('#todayDateChip').textContent=new Date().toLocaleDateString('ko-KR',{year:'numeric',month:'long',day:'numeric',weekday:'short'});
  $('#homeNetWorth').textContent=app.user?money(totals.assets):'로그인 필요';$('#homeMonthExpense').textContent=app.user?money(stats.expense):'로그인 필요';$('#homeTxCount').textContent=app.user?`${stats.rows.length}건`:'로그인 필요';$('#homeFitnessCount').textContent=`${app.fitnessRecords.length+(app.inbodyRecords?.length||0)}건`;$('#homeFitnessSub').textContent=`최근 인바디 ${latest.date||'-'} · ${latest.weight||'-'}kg`;
  $('#railNetWorth').textContent=app.user?money(totals.assets):'로그인 필요';$('#railCash').textContent=app.user?money(app.financeProfile.cash_balance):'0원';$('#railBank').textContent=app.user?money(app.financeProfile.bank_balance):'0원';$('#railSavings').textContent=app.user?money(app.financeProfile.savings_balance):'0원';$('#railAssetNote').textContent=app.user?'진서님의 보유 자산만 홈에 표시해요.':'로그인하면 진서님의 보유 자산을 불러옵니다.';
  $('#homeConsumptionSummary').textContent=app.user?consumptionSummary():`${DISPLAY_NAME}님, 로그인 후 이번 달 지출 기록을 불러오면 소비 패턴을 정리해요.`;$('#todaySummary').textContent=app.user?`${DISPLAY_NAME}님의 자산·시장·운동 기록을 오늘 기준으로 정리했어요.`:'공개 기능은 바로 사용할 수 있고, 개인 기록은 로그인 후 연결됩니다.';
  if(app.stockBrief?.items?.length){$('#homeBriefPreview').innerHTML=app.stockBrief.items.slice(0,4).map(item=>{const headline=item.headline||'최근 뉴스 흐름을 확인 중입니다.',summary=item.summary_ko||item.why_it_matters||'후속 기사와 실적 확인이 필요합니다.';return`<div class="briefline"><span class="badge ${item.stance}">${stanceLabel(item.stance)}</span><div><strong>${esc(headline)}</strong><small>${esc(item.company)} · ${esc(item.ticker)} · ${esc(summary.length>125?summary.slice(0,125)+'…':summary)}</small></div><span>→</span></div>`}).join('')}else $('#homeBriefPreview').innerHTML='<div class="empty">주식 인텔리전스에서 브리핑을 검색하면 한국어 핵심 흐름이 표시됩니다.</div>';
  renderOwnedStocks();renderNexusToday();if(app.currentPage==='fivem')renderFiveMPage()
}

const FINANCE_CATEGORIES=['식비','카페','쇼핑','생활','교통','의료','취미','고정비','이체','카드값','대출','환급','기타'];
function populateCategories(){const options=FINANCE_CATEGORIES.map(v=>`<option>${v}</option>`).join('');$('#txCategory').innerHTML=options;$('#txCategoryFilter').innerHTML='<option value="all">전체 카테고리</option>'+options;$('#txCategory').value='식비'}
function setupDropAndPaste(){const zone=$('#uploadZone'),input=$('#receiptInput');input.addEventListener('change',()=>handleTransactionFiles(input.files));['dragenter','dragover'].forEach(type=>zone.addEventListener(type,event=>{event.preventDefault();zone.classList.add('drag')}));['dragleave','drop'].forEach(type=>zone.addEventListener(type,event=>{event.preventDefault();zone.classList.remove('drag')}));zone.addEventListener('drop',event=>handleTransactionFiles(event.dataTransfer.files));document.addEventListener('paste',event=>{if(app.currentPage!=='finance')return;const files=[...event.clipboardData.items].filter(item=>item.type.startsWith('image/')).map(item=>item.getAsFile()).filter(Boolean);if(files.length)handleTransactionFiles(files)})}
function setupInbody(){const input=$('#inbodyInput');input.addEventListener('change',()=>handleInbodyFiles(input.files));$('#dietNote').addEventListener('input',()=>$('#dietAdvice').textContent=dietAdviceText($('#dietNote').value))}
async function init(){
  console.info(`[NEXUS] boot ${BUILD_ID}`);
  populateCategories();$('#txDate').value=todayStr;$('#workoutDate').value=todayStr;$('#dietDate').value=todayStr;$('#ocrBaseMonth').value=monthKey(new Date());
  applyTheme(app.theme);initNexusFeatures();setupDropAndPaste();setupInbody();renderOwnedStocks();renderImportBatchStatus();renderMiniPlayer();
  const route=parseRoute(),needsAuth=PROTECTED_PAGES.has(route.page);
  if(!needsAuth){history.replaceState(route,'',routeUrl(route));showRoute(route);renderHome()}
  else{history.replaceState({page:'home'},'',routeUrl({page:'home'}));showRoute({page:'home'});renderHome()}
  const authPromise=ensureSupabaseReady();
  runWhenIdle(()=>{renderStockMessages();renderNexusToday();if(app.currentPage==='playlist')renderPlaylists();if(app.currentPage==='guides')renderGuideCards()},700);
  await authPromise;
  if(needsAuth){if(app.user){history.replaceState(route,'',routeUrl(route));showRoute(route)}else{app.pendingRoute=route;openAuthModal()}}
  renderHome();
}
document.addEventListener('DOMContentLoaded',init);
